import{_ as o,o as t,c as s,a as e}from"./app.7df3f33c.js";var a="/assets/PlayerPianoRoll.4db73f0d.jpg",n="/assets/FL.85043a4c.png";const v=JSON.parse('{"title":"Piano roll","description":"","frontmatter":{"title":"Piano roll","subtitle":"A common form of music in modern DAWs","date":"2021-09-13T00:00:00.000Z"},"headers":[],"relativePath":"theory/notes/alternative/piano-roll/index.md"}'),l={name:"theory/notes/alternative/piano-roll/index.md"},r=e("p",null,"The Buffalo Convention of December 10, 1908 established two future roll formats for the US-producers of piano rolls for self-playing pianos. The two formats had different punchings of 65 and 88 notes, but the same width (11+1\u20444 inches or 286 millimetres); thus 65-note rolls would be perforated at 6 holes to the inch, and 88-note rolls at 9 holes to the inch, leaving margins at both ends for future developments. This made it possible to play the piano rolls on any self-playing instrument built according to the convention, albeit sometimes with a loss of special functionality. This format became a loose world standard.",-1),i=e("p",null,[e("img",{src:a,alt:""})],-1),d=e("p",null,[e("img",{src:n,alt:""})],-1),c=[r,i,d];function p(h,m,f,u,_,b){return t(),s("div",null,c)}var y=o(l,[["render",p]]);export{v as __pageData,y as default};
